import { App, nextTick } from 'vue'

export function installDevtools(app: App) {
  if (process.env.NODE_ENV === 'production') return

  window.__VUE_DEVTOOLS_GLOBAL_HOOK__ = {
    apps: [],
    register(app: App, renderer: any) {
      this.apps.push(app)
      console.log('[DevTools] Registered app')
    },
    emit(event: string, ...payload: any[]) {
      console.log(`[DevTools] ${event}`, ...payload)
    }
  }

  // Custom Vue DevTools plugin
  if (window.__VUE_DEVTOOLS_EXTENSION__) {
    window.__VUE_DEVTOOLS_EXTENSION__.connect({
      app: app._instance,
      name: 'MyApp',
      plugin: {
        install(pv) {
          pv.on.component-data = (vnode, data) => {
            if (vnode.type.name === 'ProductCard') {
              data.props = {
                ...data.props,
                devHighlight: true
              }
            }
          }
        }
      }
    })
  }

  // Expose debug utilities
  app.config.globalProperties.$debug = {
    getComponentTree: () => {
      const root = app._component
      return traverseComponents(root, 0)
    },
    getReactiveState: (obj: any) => {
      return JSON.parse(JSON.stringify(obj))
    },
    logComponentProps: (componentName: string) => {
      const instances = findComponentInstances(app, componentName)
      instances.forEach(inst => {
        console.log(`[${componentName}]`, inst.props)
      })
    }
  }
}

function traverseComponents(node: any, depth: number): string {
  if (!node) return ''
  const indent = '  '.repeat(depth)
  const name = node.type?.name || 'Anonymous'
  return `${indent}${name}\n` +
    (node.children || []).map(c => traverseComponents(c, depth + 1)).join('')
}

