import { describe, it, expect, vi } from 'vitest'
import { ref, nextTick } from 'vue'
import { useCounter } from '@/composables/useCounter'
import { mount } from '@vue/test-utils'
import CounterDisplay from '@/components/CounterDisplay.vue'

describe('useCounter', () => {
  it('should initialize with default values', () => {
    const counter = useCounter()
    expect(counter.count).toBe(0)
    expect(counter.double).toBe(0)
  })

  it('should increment count', async () => {
    const counter = useCounter(5)
    counter.increment()
    await nextTick()
    expect(counter.count).toBe(6)
    expect(counter.double).toBe(12)
  })

  it('should decrement count', async () => {
    const counter = useCounter(10)
    counter.decrement(3)
    await nextTick()
    expect(counter.count).toBe(7)
  })

  it('should not go below minimum', async () => {
    const counter = useCounter(0)
    counter.decrement(5)
    await nextTick()
    expect(counter.count).toBe(0)
  })
})

describe('CounterDisplay', () => {
  it('renders correctly', () => {
    const wrapper = mount(CounterDisplay, {
      props: { count: 42, label: 'Test' }
    })
    expect(wrapper.text()).toContain('Test: 42')
  })

  it('emits increment event', async () => {
    const wrapper = mount(CounterDisplay, {
      props: { count: 0 }
    })
    await wrapper.find('button.increment').trigger('click')
    expect(wrapper.emitted('increment')).toBeTruthy()
  })

  it('calls API on mount', async () => {
    vi.stubGlobal('fetch', vi.fn().mockResolvedValue({
      json: () => Promise.resolve({ value: 100 })
    }))
    const wrapper = mount(CounterDisplay)
    await nextTick()
    expect(fetch).toHaveBeenCalledWith('/api/counter')
  })
})

