export class ApiClient {
  private baseUrl: string
  private token: string | null

  constructor(baseUrl: string, token?: string) {
    this.baseUrl = baseUrl
    this.token = token || null
  }

  async get<T>(endpoint: string): Promise<ApiResponse<T>> {
    const headers: Record<string, string> = { 'Content-Type': 'application/json' }
    if (this.token) headers['Authorization'] = `Bearer ${this.token}`

    const response = await fetch(`${this.baseUrl}${endpoint}`, { headers })
    const data = await response.json()
    return { data, status: response.status, message: '', timestamp: new Date().toISOString() }
  }

  async post<T>(endpoint: string, body: unknown): Promise<ApiResponse<T>> {
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
      ...(this.token ? { Authorization: `Bearer ${this.token}` } : {})
    }
    const response = await fetch(`${this.baseUrl}${endpoint}`, {
      method: 'POST',
      headers,
      body: JSON.stringify(body)
    })
    const data = await response.json()
    return { data, status: response.status, message: '', timestamp: new Date().toISOString() }
  }
}

import { onMounted, onUnmounted, ref } from 'vue'

export interface PerformanceMetric {
  name: string
  duration: number
  timestamp: number
  category: 'render' | 'network' | 'interaction' | 'lifecycle'
}

export function usePerformance() {
  const metrics = ref<PerformanceMetric[]>([])
  const fps = ref(60)
  let lastFrameTime = performance.now()
  let frameCount = 0
  let rafId: number | null = null

  function measure(name: string, callback: () => void, category: PerformanceMetric['category'] = 'render') {
    const start = performance.now()
    try {
      callback()
    } finally {
      const duration = performance.now() - start
      metrics.value.push({ name, duration, timestamp: Date.now(), category })
    }
  }

  function trackFPS() {
    const checkFPS = (now: number) => {
      frameCount++
      if (now - lastFrameTime >= 1000) {
        fps.value = frameCount
        frameCount = 0
        lastFrameTime = now
      }
      rafId = requestAnimationFrame(checkFPS)
    }
    rafId = requestAnimationFrame(checkFPS)
  }

  function getSlowMetrics(threshold: number = 16): PerformanceMetric[] {
    return metrics.value.filter(m => m.duration > threshold)
  }

  function clearMetrics() {
    metrics.value = []
  }

  onMounted(() => trackFPS())
  onUnmounted(() => {
    if (rafId !== null) cancelAnimationFrame(rafId)
  })

  return { metrics, fps, measure, getSlowMetrics, clearMetrics }
}

